package com.cho2hand.marketplace.controller.notification; import com.cho2hand.marketplace.dto.notification.NotificationResponse; import com.cho2hand.marketplace.service.notification.NotificationService; import jakarta.validation.constraints.Positive; import java.util.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/notifications") public class NotificationController{private final NotificationService service;public NotificationController(NotificationService s){service=s;}@GetMapping public List<NotificationResponse> list(@AuthenticationPrincipal Long user){return service.list(user);}@PatchMapping("/{id}/read") public void read(@AuthenticationPrincipal Long user,@PathVariable @Positive Long id){service.read(user,id);}}
